# Bump pods affected percentage and duration in one command
kubectl patch chaosengine -n payments payments-pod-delete --type=merge -p '{
  "spec": {
    "experiments": [{
      "name": "pod-delete",
      "spec": {
        "components": {
          "env": [
            {"name": "TOTAL_CHAOS_DURATION", "value": "120"},
            {"name": "PODS_AFFECTED_PERC",  "value": "66"}
          ]
        }
      }
    }]
  }
}'

# Next experiment to install when pod-delete is boring
kubectl apply -n payments \
  -f https://hub.litmuschaos.io/api/chaos/3.10.0?file=charts/generic/pod-network-loss/experiment.yaml
